        <button id="__submitBtn" type="submit" style="min-height:56px;border:0;border-radius:10px;background:#d8b84a;color:#111;font-weight:900;font-size:16px;cursor:pointer;">送信する</button>
      </form>
      <script>
      (function(){
        var form = document.getElementById('__contactForm');
        if (!form) return;
        form.addEventListener('submit', async function(e) {
          e.preventDefault();
          var btn = document.getElementById('__submitBtn');
          var msg = document.getElementById('__formMsg');
          var original = btn.textContent;
          btn.disabled = true;
          btn.textContent = '送信中...';
          msg.style.display = 'none';
          var data = {};
          new FormData(form).forEach(function(v,k){ data[k] = v; });
          try {
            var res = await fetch('/contact.php', { method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(data) });
            var json = await res.json();
            msg.style.display = 'block';
            if (json.success) {
              msg.style.background = 'rgba(6,199,85,.16)';
              msg.style.border = '1px solid rgba(6,199,85,.45)';
              msg.style.color = '#8ff0b1';
              msg.textContent = json.message || '送信しました。';
              form.reset();
            } else {
              msg.style.background = 'rgba(180,40,40,.18)';
              msg.style.border = '1px solid rgba(220,80,80,.45)';
              msg.style.color = '#ffb2b2';
              msg.textContent = (json.errors || []).join(' / ') || json.message || '送信に失敗しました。';
            }
          } catch (err) {
            msg.style.display = 'block';
            msg.style.background = 'rgba(180,40,40,.18)';
            msg.style.border = '1px solid rgba(220,80,80,.45)';
            msg.style.color = '#ffb2b2';
            msg.textContent = '通信エラーが発生しました。時間をおいて再度お試しください。';
          } finally {
            btn.disabled = false;
            btn.textContent = original;
            msg.scrollIntoView({behavior:'smooth', block:'nearest'});
          }
        });
      })();
      </script>
